contracts/BridgeToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title BridgeToken (MATCOM)
 * @notice ERC20 token deployed on Sepolia as the source asset for the MATCOM Bridge.
 * @dev Initial supply is minted to the deployer. This is the "real" token that gets
 *      locked in the SepoliaBridge when bridging to Sonic Blaze.
 */
contract BridgeToken is ERC20, Ownable {
    uint8 private constant _DECIMALS = 18;

    constructor(uint256 initialSupply) ERC20("MATCOM", "MCM") Ownable(msg.sender) {
        _mint(msg.sender, initialSupply * 10 ** _DECIMALS);
    }

    function decimals() public pure override returns (uint8) {
        return _DECIMALS;
    }
}

contracts/SepoliaBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SepoliaBridge
 * @notice Bridge contract on Sepolia that locks MATCOM tokens for bridging to Sonic Blaze
 *         and releases them when bridging back.
 * @dev Uses a nonce-based replay protection system. Only the authorized relayer can
 *      call releaseTokens().
 */
contract SepoliaBridge is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;
    address public relayer;
    uint256 public nonce;

    // Track processed nonces to prevent replay
    mapping(uint256 => bool) public processedNonces;

    event TokensLocked(
        address indexed sender,
        uint256 amount,
        uint256 nonce,
        uint256 timestamp
    );

    event TokensReleased(
        address indexed recipient,
        uint256 amount,
        uint256 nonce,
        uint256 timestamp
    );

    event RelayerUpdated(address indexed oldRelayer, address indexed newRelayer);

    modifier onlyRelayer() {
        require(msg.sender == relayer, "SepoliaBridge: caller is not the relayer");
        _;
    }

    constructor(address _token) Ownable(msg.sender) {
        require(_token != address(0), "SepoliaBridge: token is zero address");
        token = IERC20(_token);
    }

    /**
     * @notice Set or update the relayer address
     * @param _relayer New relayer address
     */
    function setRelayer(address _relayer) external onlyOwner {
        require(_relayer != address(0), "SepoliaBridge: relayer is zero address");
        address oldRelayer = relayer;
        relayer = _relayer;
        emit RelayerUpdated(oldRelayer, _relayer);
    }

    /**
     * @notice Lock tokens in the bridge to initiate a cross-chain transfer to Sonic Blaze
     * @param amount Amount of tokens to lock
     */
    function lockTokens(uint256 amount) external nonReentrant {
        require(amount > 0, "SepoliaBridge: amount must be > 0");

        token.safeTransferFrom(msg.sender, address(this), amount);

        uint256 currentNonce = nonce;
        nonce++;

        emit TokensLocked(msg.sender, amount, currentNonce, block.timestamp);
    }

    /**
     * @notice Release tokens back to a user (called by relayer when tokens are burned on Sonic)
     * @param to Recipient address
     * @param amount Amount of tokens to release
     * @param _nonce Nonce from the burn event on Sonic (for replay protection)
     */
    function releaseTokens(
        address to,
        uint256 amount,
        uint256 _nonce
    ) external onlyRelayer nonReentrant {
        require(to != address(0), "SepoliaBridge: recipient is zero address");
        require(amount > 0, "SepoliaBridge: amount must be > 0");
        require(!processedNonces[_nonce], "SepoliaBridge: nonce already processed");

        processedNonces[_nonce] = true;
        token.safeTransfer(to, amount);

        emit TokensReleased(to, amount, _nonce, block.timestamp);
    }

    /**
     * @notice Get the bridge's token balance (locked tokens)
     */
    function getLockedBalance() external view returns (uint256) {
        return token.balanceOf(address(this));
    }
}

contracts/SonicBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./WrappedToken.sol";

/**
 * @title SonicBridge
 * @notice Bridge contract on Sonic Blaze that mints wrapped MATCOM when tokens
 *         are locked on Sepolia, and burns them when users want to bridge back.
 * @dev Uses nonce-based replay protection. Only the authorized relayer can mint.
 */
contract SonicBridge is Ownable, ReentrancyGuard {
    WrappedToken public immutable wrappedToken;
    address public relayer;
    uint256 public nonce;

    // Track processed nonces from Sepolia to prevent replay
    mapping(uint256 => bool) public processedNonces;

    event TokensMinted(
        address indexed recipient,
        uint256 amount,
        uint256 nonce,
        uint256 timestamp
    );

    event TokensBurned(
        address indexed sender,
        uint256 amount,
        uint256 nonce,
        uint256 timestamp
    );

    event RelayerUpdated(address indexed oldRelayer, address indexed newRelayer);

    modifier onlyRelayer() {
        require(msg.sender == relayer, "SonicBridge: caller is not the relayer");
        _;
    }

    constructor(address _wrappedToken) Ownable(msg.sender) {
        require(_wrappedToken != address(0), "SonicBridge: token is zero address");
        wrappedToken = WrappedToken(_wrappedToken);
    }

    /**
     * @notice Set or update the relayer address
     * @param _relayer New relayer address
     */
    function setRelayer(address _relayer) external onlyOwner {
        require(_relayer != address(0), "SonicBridge: relayer is zero address");
        address oldRelayer = relayer;
        relayer = _relayer;
        emit RelayerUpdated(oldRelayer, _relayer);
    }

    /**
     * @notice Mint wrapped tokens to a user (called by relayer when tokens are locked on Sepolia)
     * @param to Recipient address
     * @param amount Amount to mint
     * @param _nonce Nonce from the lock event on Sepolia (for replay protection)
     */
    function mintWrapped(
        address to,
        uint256 amount,
        uint256 _nonce
    ) external onlyRelayer nonReentrant {
        require(to != address(0), "SonicBridge: recipient is zero address");
        require(amount > 0, "SonicBridge: amount must be > 0");
        require(!processedNonces[_nonce], "SonicBridge: nonce already processed");

        processedNonces[_nonce] = true;
        wrappedToken.mint(to, amount);

        emit TokensMinted(to, amount, _nonce, block.timestamp);
    }

    /**
     * @notice Burn wrapped tokens to initiate bridging back to Sepolia
     * @param amount Amount of wrapped tokens to burn
     */
    function burnWrapped(uint256 amount) external nonReentrant {
        require(amount > 0, "SonicBridge: amount must be > 0");

        uint256 currentNonce = nonce;
        nonce++;

        wrappedToken.burn(msg.sender, amount);

        emit TokensBurned(msg.sender, amount, currentNonce, block.timestamp);
    }

    /**
     * @notice Get total supply of wrapped tokens
     */
    function getTotalMinted() external view returns (uint256) {
        return wrappedToken.totalSupply();
    }
}

contracts/WrappedToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title WrappedToken (Wrapped MATCOM)
 * @notice Wrapped ERC20 token on Sonic Blaze representing bridged MATCOM tokens.
 * @dev Only the bridge contract can mint/burn these tokens.
 */
contract WrappedToken is ERC20, Ownable {
    uint8 private constant _DECIMALS = 18;
    address public bridge;

    event BridgeUpdated(address indexed oldBridge, address indexed newBridge);

    modifier onlyBridge() {
        require(msg.sender == bridge, "WrappedToken: caller is not the bridge");
        _;
    }

    constructor() ERC20("Wrapped MATCOM", "wMCM") Ownable(msg.sender) {}

    function decimals() public pure override returns (uint8) {
        return _DECIMALS;
    }

    /**
     * @notice Set the bridge contract address (only bridge can mint/burn)
     * @param _bridge Address of the SonicBridge contract
     */
    function setBridge(address _bridge) external onlyOwner {
        require(_bridge != address(0), "WrappedToken: bridge is zero address");
        address oldBridge = bridge;
        bridge = _bridge;
        emit BridgeUpdated(oldBridge, _bridge);
    }

    /**
     * @notice Mint wrapped tokens (called by bridge when tokens are locked on Sepolia)
     * @param to Recipient address
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) external onlyBridge {
        _mint(to, amount);
    }

    /**
     * @notice Burn wrapped tokens (called by bridge when user wants to bridge back)
     * @param from Address to burn from
     * @param amount Amount to burn
     */
    function burn(address from, uint256 amount) external onlyBridge {
        _burn(from, amount);
    }
}

